html, body {
  background: #ffffff !important;
  margin: 0;
  padding: 0;
}

.app {
  height: calc(var(--appsmith-ui-height) * 1px);
  width: calc(var(--appsmith-ui-width) * 1px);
  padding: 8px;
  box-sizing: border-box;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.ag-theme-alpine {
  --ag-header-background-color: #FFFFFF;
  --ag-header-foreground-color: #0F2A47;
  --ag-odd-row-background-color: #ffffff;
  --ag-even-row-background-color: #FAFBFC;
  --ag-row-hover-color: #E8F0FA;
  --ag-selected-row-background-color: #E8F0FA;
  --ag-foreground-color: #1A1A1A;
  --ag-border-color: #e5e7eb;
  --ag-font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  --ag-font-size: 14px; --ag-row-height: 44px; --ag-header-height: 48px;
  border-radius: 6px;
  border: none;
}

.ag-theme-alpine .ag-header {
  font-weight: 600;
  border-bottom: 1px solid #D1D5DB;
}

.ag-theme-alpine .ag-header-cell-text {
  color: #0F2A47;
}

.ag-theme-alpine .ag-header-cell-menu-button {
  opacity: 1 !important;
}

.ag-theme-alpine .ag-paging-button.ag-paging-button-current,
.ag-theme-alpine .ag-paging-page-summary-panel .ag-paging-button[disabled] {
  background: #0F2A47;
  color: #FFFFFF;
  border-radius: 50%;
}

.ag-theme-alpine .ag-paging-panel {
  color: #6B7280;
  border-top: 1px solid #E5E7EB;
}

.ag-menu, .ag-menu-option, .ag-tooltip {
  z-index: 999999 !important;
}

