function pretty(k) {
  return k.charAt(0).toUpperCase() + k.slice(1).replace(/([A-Z])/g, ' $1').replace(/__/g, ' · ').trim();
}
function normalize(model) {
  return Array.isArray(model && model.rows) ? model.rows : [];
}
function columnsFor(rows, picked) {
  const fields = Array.isArray(picked) && picked.length > 0 ? picked : rows[0] ? Object.keys(rows[0]) : [];
  return fields.map(f => ({
    headerName: pretty(f),
    field: f,
    valueFormatter: p => p.value && typeof p.value === 'object' ? JSON.stringify(p.value) : p.value
  }));
}
let gridApi = null;
function renderGrid(model) {
  const rowData = normalize(model);
  const columnDefs = columnsFor(rowData, model && model.columns);
  const gridOptions = {
    columnDefs,
    rowData,
    pagination: true,
    paginationPageSize: 50,
    paginationPageSizeSelector: [25, 50, 100, 200, 500],
    defaultColDef: {
      sortable: true,
      resizable: true,
      filter: true,
      enableRowGroup: true,
      editable: false,
      minWidth: 120,
      menuTabs: ['generalMenuTab', 'filterMenuTab', 'columnsMenuTab']
    },
    animateRows: true,
    popupParent: document.body,
    rowGroupPanelShow: 'onlyWhenGrouping',
    pivotMode: false,
    onGridReady: params => {
      gridApi = params.api;
    }
  };
  const gridDiv = document.querySelector('#myGrid');
  if (!gridDiv) return;
  gridDiv.innerHTML = '';
  gridApi = agGrid.createGrid(gridDiv, gridOptions);
}
appsmith.onReady(() => {
  renderGrid(appsmith.model);
  appsmith.onModelChange(renderGrid);
});

